<template>
    <scroll-view 
      scroll-y 
      class="right-content" 
      :scroll-top="scrollTop" 
      scroll-with-animation
      @scroll="onScroll"
    >
      <view v-for="cat in categories" :key="cat.id" class="category-section" :id="'section-' + cat.id">
        <view class="category-title">{{ cat.name }}</view>
        
        <view v-for="product in cat.products" :key="product.id" class="product-item">
          <image class="product-img" :src="product.image || '/static/logo.png'" mode="aspectFill"></image>
          <view class="product-info">
            <view>
              <text class="name">{{ product.name }}</text>
              <text class="desc">{{ product.description }}</text>
            </view>
            <view class="price-row">
              <text class="price">¥{{ product.price }}</text>
              <view class="add-btn" @click.stop="$emit('add', product.id, 1)">+</view>
            </view>
          </view>
        </view>
      </view>
      
      <view class="bottom-placeholder"></view>
    </scroll-view>
  </template>
  
  <script setup>
  /**
   * 商品列表组件
   * @property {Array} categories 分类及商品数据
   * @property {Number} scrollTop 外部控制的滚动位置
   */
  defineProps({
    categories: {
      type: Array,
      default: () => []
    },
    scrollTop: {
      type: Number,
      default: 0
    }
  });
  
  const emit = defineEmits(['add', 'scroll']);
  
  // 监听滚动事件，并向上抛出
  const onScroll = (e) => {
    emit('scroll', e.detail.scrollTop);
  };
  </script>
  
  <style lang="scss" scoped>
  $theme-color: #023993;
  
  .right-content {
    flex: 1;
    height: 100%;
    background-color: #fff;
    padding: 0 20rpx;
  
    .category-title {
      padding: 24rpx 0;
      font-size: 24rpx;
      color: #999;
      font-weight: bold;
      background-color: #fff;
      /* 吸顶效果（可选） */
      position: sticky;
      top: 0;
      z-index: 5;
    }
  
    .product-item {
      display: flex;
      margin-bottom: 40rpx;
      
      .product-img { 
        width: 160rpx; 
        height: 160rpx; 
        border-radius: 12rpx; 
        background-color: #f5f5f5; 
        flex-shrink: 0;
      }
      
      .product-info {
        flex: 1;
        margin-left: 20rpx;
        display: flex;
        flex-direction: column;
        justify-content: space-between;
        
        .name { 
          font-size: 30rpx; 
          font-weight: bold; 
          display: block;
          color: #333;
        }
        
        .desc { 
          font-size: 22rpx; 
          color: #999; 
          line-height: 1.4;
          margin-top: 4rpx;
          display: block;
        }
        
        .price-row {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-top: 10rpx;
          
          .price { 
            font-size: 32rpx; 
            font-weight: bold; 
            color: #333; 
          }
          
          .add-btn {
            width: 44rpx;
            height: 44rpx;
            background-color: $theme-color;
            color: #fff;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 36rpx;
            box-shadow: 0 4rpx 8rpx rgba($theme-color, 0.3);
            
            &:active {
              transform: scale(0.9);
              opacity: 0.8;
            }
          }
        }
      }
    }
    
    .bottom-placeholder { 
      height: 150rpx; 
    }
  }
  </style>